            }
        }
    }

    let mut lines: Vec<String> = Vec::new();

    if removed.is_empty() && errors.is_empty() {
        lines.push("Nothing to absolve.".to_string());
    } else {
        if !removed.is_empty() {
            lines.push(format!("Absolved {} officium/officia:", removed.len()));

