                let p = deser!(jjrm_ShowParams);
                let mut gazette = jjrz_Gazette::jjrz_build(&[jjrz_Slug::Paddock, jjrz_Slug::Pace]);
                let result = jjrpd_run_parade(jjrpd_ParadeArgs {
