  4→
  5→//! Fundus scenario tests for remote dispatch via SSH.
  6→//!
  7→//! Run via tabtargets:
  8→//!   Suite:  `tt/jjw-tfs.TestFundusScenario.<host>.sh`
  9→//!   Single: `tt/jjw-tfS.TestFundusSingle.<host>.sh <test_fn>`
 10→//!
 11→//! Requires jjfu_* accounts on the target host — see JJSTF-test-fundus.adoc.
 12→//!
 13→//! All tests use `#[ignore]` to prevent running during normal `cargo test`.
 14→//! The workbench invokes with `--ignored` after setting JJTEST_HOST.
 15→//!
 16→//! Relay tests mint real pensa (creating git commits). This is intentional —
 17→//! these are end-to-end scenario tests run explicitly via tabtarget.
 18→
 19→use std::path::PathBuf;
 20→
 21→use jjk::jjrlg_legatio::{
 22→    jjrlg_BindArgs, jjrlg_run_bind,
 23→    jjrlg_SendArgs, jjrlg_run_send,
 24→    jjrlg_PlantArgs, jjrlg_run_plant,
 25→    jjrlg_FetchArgs, jjrlg_run_fetch,
 26→    jjrlg_RelayArgs, jjrlg_run_relay,
 27→    jjrlg_CheckArgs, jjrlg_run_check,
 28→};
 29→
 30→// ============================================================================
 31→// Account names — jjfu_* (JJ Fundus User)
 32→// ============================================================================
 33→
 34→const JJFU_FULL: &str = "jjfu_full";
 35→const JJFU_NOKEY: &str = "jjfu_nokey";
 36→const JJFU_NOREPO: &str = "jjfu_norepo";
 37→const JJFU_NOGIT: &str = "jjfu_nogit";
 38→
 39→// ============================================================================
 40→// Shared constants
 41→// ============================================================================
 42→
 43→/// Relative directory for fundus projects (shared across all accounts).
 44→const RELDIR: &str = "projects/rbm_alpha_recipemuster";
 45→
 46→/// Tabtarget for relay tests — quick, safe, goes through BUD dispatch.
 47→const RELAY_TEST_TABTARGET: &str = "buw-rcr.RenderConfigRegime.sh";
 48→
 49→/// Delay tabtarget for concurrent overlap tests — 20s sleep through BUD dispatch.
 50→const DELAY_TABTARGET: &str = "buw-xd.Delay.sh";
 51→
 52→/// Relay timeout (seconds). Self-enforced remotely via watchdog.
 53→const RELAY_TEST_TIMEOUT: u64 = 60;
 54→
 55→/// Check poll timeout (seconds). How long to wait for completion.
 56→const CHECK_POLL_TIMEOUT: u64 = 30;
 57→
 58→/// Delay check poll timeout (seconds). Must exceed the 20s sleep plus dispatch overhead.
 59→const DELAY_CHECK_TIMEOUT: u64 = 60;
 60→
 61→/// Firemark for relay tests. Pensum minting validates against gallops,
 62→/// so this must be a real racing heat.
 63→const RELAY_TEST_FIREMARK: &str = "A4";
 64→
 65→// ============================================================================
 66→// Project root — cargo test CWD is the crate dir, not the project root.
 67→// JJK library code uses relative paths from project root. Tests run with
 68→// --test-threads=1, so set_current_dir is safe.
 69→// ============================================================================
 70→
 71→fn ensure_project_root() {
 72→    use std::sync::Once;
 73→    static INIT: Once = Once::new();
 74→    INIT.call_once(|| {
 75→        let root = PathBuf::from(env!("CARGO_MANIFEST_DIR"))
 76→            .parent().unwrap()    // Tools/jjk
 77→            .parent().unwrap()    // Tools
 78→            .parent().unwrap()    // project root
 79→            .to_path_buf();
 80→        std::env::set_current_dir(&root)
 81→            .unwrap_or_else(|e| panic!("set_current_dir to {}: {}", root.display(), e));
 82→    });
 83→}
 84→
 85→// ============================================================================
 86→// Host resolution
 87→// ============================================================================
 88→
 89→/// Read target host from JJTEST_HOST (set by workbench from tabtarget imprint).
 90→fn test_host() -> String {
 91→    std::env::var("JJTEST_HOST")
 92→        .unwrap_or_else(|_| panic!("JJTEST_HOST not set — run via tabtarget"))
 93→}
 94→
 95→// ============================================================================
 96→// Test officium (RAII)
 97→// ============================================================================
 98→
 99→/// Temporary officium directory for scenario tests.
100→/// Cleaned up on drop, even on panic.
101→struct TestOfficium {
102→    id: String,
103→    dir: PathBuf,
104→}
105→
106→impl TestOfficium {
107→    fn new(label: &str) -> Self {
108→        ensure_project_root();
109→        let ts = chrono::Local::now().format("%H%M%S%.3f").to_string();
110→        let bare_id = format!("test-{}-{}", label, ts);
111→        let dir = PathBuf::from(".claude/jjm/officia").join(&bare_id);
112→        std::fs::create_dir_all(&dir)
113→            .unwrap_or_else(|e| panic!("create test officium {}: {}", dir.display(), e));
114→        Self {
115→            id: format!("\u{2609}{}", bare_id), // ☉ prefix
116→            dir,
117→        }
118→    }
119→}
120→
121→impl Drop for TestOfficium {
122→    fn drop(&mut self) {
123→        let _ = std::fs::remove_dir_all(&self.dir);
124→    }
125→}
126→
127→// ============================================================================
128→// Profile configuration
129→// ============================================================================
130→
131→struct FundusProfile {
132→    host: String,
133→    user: String,
134→    reldir: String,
135→}
136→
137→// ============================================================================
138→// Preflight
139→// ============================================================================
140→
141→fn preflight_ssh(host: &str, user: &str) -> bool {
142→    std::process::Command::new("ssh")
143→        .args(["-o", "ConnectTimeout=5", "-o", "BatchMode=yes"])
144→        .arg(format!("{}@{}", user, host))
145→        .arg("exit 0")
146→        .output()
147→        .map(|o| o.status.success())
148→        .unwrap_or(false)
149→}
150→
151→fn preflight_happy(p: &FundusProfile) -> Result<(), String> {
152→    if !preflight_ssh(&p.host, &p.user) {
153→        return Err(format!("SSH to {}@{} failed", p.user, p.host));
154→    }
155→    let ssh_test = |cmd: &str| -> bool {
156→        std::process::Command::new("ssh")
157→            .args(["-o", "ConnectTimeout=5", "-o", "BatchMode=yes"])
158→            .arg(format!("{}@{}", p.user, p.host))
159→            .arg(cmd)
160→            .output()
161→            .map(|o| o.status.success())
162→            .unwrap_or(false)
163→    };
164→    if !ssh_test(&format!("test -d $HOME/{}", p.reldir)) {
165→        return Err(format!("reldir not found: $HOME/{}", p.reldir));
166→    }
167→    if !ssh_test(&format!("test -f $HOME/{}/.buk/burc.env", p.reldir)) {
168→        return Err("BUK not installed: .buk/burc.env missing".to_string());
169→    }
170→    // Dispatch smoke: run a trivial tabtarget through BUD to verify station regime etc.
171→    let smoke = std::process::Command::new("ssh")
172→        .args(["-o", "ConnectTimeout=10", "-o", "BatchMode=yes"])
173→        .arg(format!("{}@{}", p.user, p.host))
174→        .arg(format!("cd $HOME/{} && ./tt/buw-rcr.RenderConfigRegime.sh >/dev/null 2>&1", p.reldir))
175→        .output();
176→    match smoke {
177→        Ok(o) if o.status.success() => Ok(()),
178→        Ok(o) => Err(format!("BUD dispatch smoke failed (exit {}) — check station regime (burs.env)",
179→            o.status.code().unwrap_or(-1))),
180→        Err(e) => Err(format!("BUD dispatch smoke SSH error: {}", e)),
181→    }
182→}
183→
184→// ============================================================================
185→// Output parsing helpers
186→// ============================================================================
187→
188→/// Parse legatio token from bind output ("Legatio L0 bound to ...").
189→fn parse_legatio_token(output: &str) -> String {
190→    output.lines()
191→        .find(|l| l.contains("Legatio ") && l.contains(" bound to "))
192→        .and_then(|l| {
193→            let rest = l.split("Legatio ").nth(1)?;
194→            rest.split_whitespace().next()
195→        })
196→        .unwrap_or_else(|| panic!("cannot parse legatio token from:\n{}", output))
197→        .to_string()
198→}
199→
200→/// Parse pensum display from relay output ("Pensum ₱XX%YY active.").
201→fn parse_pensum_display(output: &str) -> String {
202→    output.lines()
203→        .find(|l| l.contains("Pensum ") && l.contains(" active."))
204→        .and_then(|l| {
205→            let rest = l.split("Pensum ").nth(1)?;
206→            rest.split_whitespace().next()
207→        })
208→        .unwrap_or_else(|| panic!("cannot parse pensum from:\n{}", output))
209→        .to_string()
210→}
211→
212→/// Strip ₱ (U+20B1) prefix from pensum display to get raw token.
213→fn pensum_raw_token(display: &str) -> &str {
214→    display.trim_start_matches('\u{20B1}')
215→}
216→
217→// ============================================================================
218→// Shared test operations
219→// ============================================================================
220→
221→/// Bind to a fundus profile and return the legatio token.
222→fn bind_profile(p: &FundusProfile, officium: &TestOfficium) -> String {
223→    let (code, output) = jjrlg_run_bind(
224→        jjrlg_BindArgs {
225→            host: p.host.clone(),
226→            user: p.user.clone(),
227→            reldir: p.reldir.clone(),
228→        },
229→        &officium.id,
230→    );
231→    assert_eq!(code, 0, "bind failed:\n{}", output);
232→    parse_legatio_token(&output)
233→}
234→
235→
236→// ============================================================================
237→// Output extraction helpers
238→// ============================================================================
239→
240→/// Extract a BURX field value from check output (e.g., "BURX_LABEL:value" → "value").
241→fn extract_burx_field(output: &str, field: &str) -> String {
242→    let prefix = format!("{}:", field);
243→    output.lines()
244→        .find(|l| l.starts_with(&prefix))
245→        .map(|l| l[prefix.len()..].trim().to_string())
246→        .unwrap_or_else(|| panic!("missing {} in output:\n{}", field, output))
247→}
248→
249→// ============================================================================
250→// Happy-path test implementations (jjfu_full)
251→// ============================================================================
252→
253→fn test_bind_send_impl(p: &FundusProfile) {
254→    let officium = TestOfficium::new("bind-send");
255→    let token = bind_profile(p, &officium);
256→
257→    let (code, output) = jjrlg_run_send(
258→        jjrlg_SendArgs {
259→            legatio: token,
260→            command: "echo hello_from_fundus".to_string(),
261→        },
262→        &officium.id,
263→    );
264→    assert_eq!(code, 0, "send failed:\n{}", output);
265→    assert!(output.contains("hello_from_fundus"), "missing echo output:\n{}", output);
266→    assert!(output.contains("Exit: 0"), "expected exit 0:\n{}", output);
267→}
268→
269→fn test_plant_impl(p: &FundusProfile) {
270→    let officium = TestOfficium::new("plant");
271→    let token = bind_profile(p, &officium);
272→
273→    // Get curia HEAD
274→    let head = std::process::Command::new("git")
275→        .args(["rev-parse", "HEAD"])
276→        .output()
277→        .expect("git rev-parse HEAD");
278→    let commit = String::from_utf8_lossy(&head.stdout).trim().to_string();
279→    assert!(!commit.is_empty(), "failed to get HEAD commit");
280→
281→    let (code, output) = jjrlg_run_plant(
282→        jjrlg_PlantArgs {
283→            legatio: token.clone(),
284→            commit: commit.clone(),
285→        },
286→        &officium.id,
287→    );
288→    assert_eq!(code, 0, "plant failed:\n{}", output);
289→    assert!(output.contains("Plant succeeded"), "no success message:\n{}", output);
290→
291→    // Verify fundus HEAD matches
292→    let (sc, so) = jjrlg_run_send(
293→        jjrlg_SendArgs {
294→            legatio: token,
295→            command: "git rev-parse HEAD".to_string(),
296→        },
297→        &officium.id,
298→    );
299→    assert_eq!(sc, 0, "send after plant failed:\n{}", so);
300→    assert!(so.contains(&commit), "fundus HEAD mismatch:\n{}", so);
301→}
