306→    let officium = TestOfficium::new("relay-inst");
307→    let token = bind_profile(p, &officium);
308→
309→    let (code, output) = jjrlg_run_relay(
310→        jjrlg_RelayArgs {
311→            legatio: token,
312→            tabtarget: RELAY_TEST_TABTARGET.to_string(),
313→            timeout: RELAY_TEST_TIMEOUT,
314→            firemark,
315→        },
316→        &officium.id,
317→    );
318→    assert_eq!(code, 0, "relay failed:\n{}", output);
319→    let pensum = parse_pensum_display(&output);
320→
321→    // Instant probe (timeout=0) — tabtarget may already be done
322→    let (cc, co) = jjrlg_run_check(
323→        jjrlg_CheckArgs { pensum, timeout: 0 },
324→        &officium.id,
325→    );
326→    assert_eq!(cc, 0, "check failed:\n{}", co);
327→    assert!(
328→        co.contains("Report: running") || co.contains("Report: stopped"),
329→        "unexpected report:\n{}", co
330→    );
331→}
