361→    // BURX_LABEL correlation: pensum token round-trips through BURE_LABEL → BURX_LABEL
362→    let label_line = co.lines()
363→        .find(|l| l.starts_with("BURX_LABEL:"))
364→        .unwrap_or_else(|| panic!("no BURX_LABEL in check output:\n{}", co));
365→    assert!(
366→        label_line.contains(raw),
367→        "BURX_LABEL mismatch: expected '{}' in '{}'\nfull output:\n{}", raw, label_line, co
368→    );
369→
370→    // File list on terminal status
371→    assert!(co.contains("Files:"), "no file list on terminal status:\n{}", co);
372→    assert!(co.contains("burx.env"), "burx.env not in file list:\n{}", co);
373→}
