375→fn test_relay_parallel_impl(p: &FundusProfile) {
376→    let firemark = RELAY_TEST_FIREMARK.to_string();
377→
378→    let officium = TestOfficium::new("relay-par");
379→    let token = bind_profile(p, &officium);
380→
381→    // Dispatch 3 concurrent jobs
382→    let mut pensa = Vec::new();
383→    for i in 0..3 {
384→        let (code, output) = jjrlg_run_relay(
385→            jjrlg_RelayArgs {
386→                legatio: token.clone(),
387→                tabtarget: RELAY_TEST_TABTARGET.to_string(),
388→                timeout: RELAY_TEST_TIMEOUT,
389→                firemark: firemark.clone(),
390→            },
391→            &officium.id,
392→        );
393→        assert_eq!(code, 0, "relay {} failed:\n{}", i, output);
394→        pensa.push(parse_pensum_display(&output));
395→    }
396→
397→    // Verify all 3 complete independently with distinct labels
398→    let mut labels = Vec::new();
399→    for (i, pensum) in pensa.iter().enumerate() {
400→        let (cc, co) = jjrlg_run_check(
401→            jjrlg_CheckArgs { pensum: pensum.clone(), timeout: CHECK_POLL_TIMEOUT },
402→            &officium.id,
403→        );
404→        assert_eq!(cc, 0, "check {} failed:\n{}", i, co);
405→        assert!(co.contains("Report: stopped"), "pensum {} not stopped:\n{}", i, co);
406→
407→        if let Some(line) = co.lines().find(|l| l.starts_with("BURX_LABEL:")) {
408→            labels.push(line.to_string());
409→        }
410→    }
411→
412→    // No cross-contamination: all labels must be distinct
413→    for i in 0..labels.len() {
414→        for j in (i + 1)..labels.len() {
415→            assert_ne!(
416→                labels[i], labels[j],
417→                "cross-contamination: pensa {} and {} share label", i, j
418→            );
419→        }
420→    }
421→}
