429→    // Dispatch 3 concurrent relay jobs using the delay tabtarget
430→    let mut pensa = Vec::new();
431→    for i in 0..3 {
432→        let (code, output) = jjrlg_run_relay(
433→            jjrlg_RelayArgs {
434→                legatio: token.clone(),
435→                tabtarget: DELAY_TABTARGET.to_string(),
436→                timeout: RELAY_TEST_TIMEOUT,
437→                firemark: firemark.clone(),
438→            },
439→            &officium.id,
440→        );
441→        assert_eq!(code, 0, "relay {} failed:\n{}", i, output);
442→        pensa.push(parse_pensum_display(&output));
443→    }
444→
445→    // Instant-probe all 3 — 20s sleep guarantees temporal overlap
446→    for (i, pensum) in pensa.iter().enumerate() {
447→        let (cc, co) = jjrlg_run_check(
448→            jjrlg_CheckArgs { pensum: pensum.clone(), timeout: 0 },
449→            &officium.id,
450→        );
451→        assert_eq!(cc, 0, "instant check {} failed:\n{}", i, co);
452→        assert!(
453→            co.contains("Report: running"),
454→            "pensum {} not running (20s sleep should guarantee overlap):\n{}", i, co
455→        );
456→    }
457→
458→    // Poll all 3 to completion, collecting labels and temp dirs
459→    let mut labels = Vec::new();
460→    let mut temp_dirs = Vec::new();
461→    for (i, pensum) in pensa.iter().enumerate() {
462→        let (cc, co) = jjrlg_run_check(
463→            jjrlg_CheckArgs { pensum: pensum.clone(), timeout: DELAY_CHECK_TIMEOUT },
464→            &officium.id,
