466→        assert_eq!(cc, 0, "poll check {} failed:\n{}", i, co);
467→        assert!(co.contains("Report: stopped"), "pensum {} not stopped:\n{}", i, co);
468→
469→        // Verify BURX_LABEL correlates with pensum token
470→        let raw = pensum_raw_token(pensum);
471→        let label = extract_burx_field(&co, "BURX_LABEL");
472→        assert!(
473→            label.contains(raw),
474→            "pensum {} BURX_LABEL mismatch: expected '{}' in '{}'", i, raw, label
475→        );
476→
477→        labels.push(label);
478→        temp_dirs.push(extract_burx_field(&co, "BURX_TEMP_DIR"));
479→    }
480→
481→    // No cross-contamination: all labels must be distinct
482→    for i in 0..labels.len() {
483→        for j in (i + 1)..labels.len() {
484→            assert_ne!(
485→                labels[i], labels[j],
486→                "cross-contamination: pensa {} and {} share BURX_LABEL", i, j
487→            );
488→        }
489→    }
490→
491→    // Isolation: all temp dirs must be distinct
492→    for i in 0..temp_dirs.len() {
493→        for j in (i + 1)..temp_dirs.len() {
494→            assert_ne!(
495→                temp_dirs[i], temp_dirs[j],
496→                "isolation failure: pensa {} and {} share BURX_TEMP_DIR", i, j
497→            );
498→        }
499→    }
