            &officium.id,
        );
        assert_eq!(code, 0, "send should work without git:\n{}", output);
        assert!(output.contains("nogit_works"), "missing echo output:\n{}", output);
    }

    #[test] #[ignore]
    fn plant_fails() {
        let p = profile();
