423→fn test_relay_parallel_impl(p: &FundusProfile) {
424→    let firemark = RELAY_TEST_FIREMARK.to_string();
425→
426→    let officium = TestOfficium::new("relay-par");
427→    let token = bind_profile(p, &officium);
428→
429→    // Dispatch 3 concurrent jobs
430→    let mut pensa = Vec::new();
431→    for i in 0..3 {
432→        let (code, output) = jjrlg_run_relay(
433→            jjrlg_RelayArgs {
434→                legatio: token.clone(),
435→                tabtarget: RELAY_TEST_TABTARGET.to_string(),
436→                timeout: RELAY_TEST_TIMEOUT,
437→                firemark: firemark.clone(),
438→            },
439→            &officium.id,
440→        );
441→        assert_eq!(code, 0, "relay {} failed:\n{}", i, output);
442→        pensa.push(parse_pensum_display(&output));
443→    }
444→
445→    // Verify all 3 complete independently with distinct labels
446→    let mut labels = Vec::new();
447→    for (i, pensum) in pensa.iter().enumerate() {
448→        let (cc, co) = jjrlg_run_check(
449→            jjrlg_CheckArgs { pensum: pensum.clone(), timeout: CHECK_POLL_TIMEOUT },
450→            &officium.id,
451→        );
452→        assert_eq!(cc, 0, "check {} failed:\n{}", i, co);
453→        assert!(co.contains("Report: stopped"), "pensum {} not stopped:\n{}", i, co);
454→
455→        if let Some(line) = co.lines().find(|l| l.starts_with("BURX_LABEL:")) {
456→            labels.push(line.to_string());
457→        }
458→    }
459→
460→    // No cross-contamination: all labels must be distinct
461→    for i in 0..labels.len() {
462→        for j in (i + 1)..labels.len() {
463→            assert_ne!(
464→                labels[i], labels[j],
465→                "cross-contamination: pensa {} and {} share label", i, j
466→            );
467→        }
468→    }
469→}
