471→fn test_relay_concurrent_overlap_impl(p: &FundusProfile) {
472→    let firemark = RELAY_TEST_FIREMARK.to_string();
473→
474→    let officium = TestOfficium::new("relay-conc");
475→    let token = bind_profile(p, &officium);
476→
477→    // Dispatch 3 concurrent relay jobs using the delay tabtarget
478→    let mut pensa = Vec::new();
479→    for i in 0..3 {
480→        let (code, output) = jjrlg_run_relay(
481→            jjrlg_RelayArgs {
482→                legatio: token.clone(),
483→                tabtarget: DELAY_TABTARGET.to_string(),
484→                timeout: RELAY_TEST_TIMEOUT,
485→                firemark: firemark.clone(),
486→            },
487→            &officium.id,
488→        );
489→        assert_eq!(code, 0, "relay {} failed:\n{}", i, output);
490→        pensa.push(parse_pensum_display(&output));
491→    }
492→
493→    // Instant-probe all 3 — 20s sleep guarantees temporal overlap
494→    for (i, pensum) in pensa.iter().enumerate() {
495→        let (cc, co) = jjrlg_run_check(
496→            jjrlg_CheckArgs { pensum: pensum.clone(), timeout: 0 },
497→            &officium.id,
498→        );
499→        assert_eq!(cc, 0, "instant check {} failed:\n{}", i, co);
500→        assert!(
501→            co.contains("Report: running"),
502→            "pensum {} not running (20s sleep should guarantee overlap):\n{}", i, co
503→        );
504→    }
505→
506→    // Poll all 3 to completion, collecting labels and temp dirs
507→    let mut labels = Vec::new();
508→    let mut temp_dirs = Vec::new();
509→    for (i, pensum) in pensa.iter().enumerate() {
510→        let (cc, co) = jjrlg_run_check(
511→            jjrlg_CheckArgs { pensum: pensum.clone(), timeout: DELAY_CHECK_TIMEOUT },
512→            &officium.id,
513→        );
514→        assert_eq!(cc, 0, "poll check {} failed:\n{}", i, co);
515→        assert!(co.contains("Report: stopped"), "pensum {} not stopped:\n{}", i, co);
516→
517→        // Verify BURX_LABEL correlates with pensum token
518→        let raw = pensum_raw_token(pensum);
519→        let label = extract_burx_field(&co, "BURX_LABEL");
520→        assert!(
521→            label.contains(raw),
522→            "pensum {} BURX_LABEL mismatch: expected '{}' in '{}'", i, raw, label
523→        );
524→
525→        labels.push(label);
526→        temp_dirs.push(extract_burx_field(&co, "BURX_TEMP_DIR"));
527→    }
528→
529→    // No cross-contamination: all labels must be distinct
530→    for i in 0..labels.len() {
531→        for j in (i + 1)..labels.len() {
532→            assert_ne!(
533→                labels[i], labels[j],
534→                "cross-contamination: pensa {} and {} share BURX_LABEL", i, j
535→            );
536→        }
537→    }
538→
539→    // Isolation: all temp dirs must be distinct
540→    for i in 0..temp_dirs.len() {
541→        for j in (i + 1)..temp_dirs.len() {
542→            assert_ne!(
543→                temp_dirs[i], temp_dirs[j],
544→                "isolation failure: pensa {} and {} share BURX_TEMP_DIR", i, j
545→            );
546→        }
547→    }
548→}
