            reldir: RELDIR.to_string(),
        };
        preflight_happy(&p).unwrap_or_else(|e| panic!(
            "full profile not available ({}@{}): {}\nProvision: sudo tt/jjw-tfP.ProvisionFundusAccounts.localhost.sh",
            JJFU_FULL, p.host, e));
        p
    }

    #[test] #[ignore]
    fn bind_send() { test_bind_send_impl(&profile()); }

    #[test] #[ignore]
