        jjrlg_FetchArgs {
            legatio: token,
            path: "/etc/shells".to_string(),
        },
        &officium.id,
    );
    assert_eq!(ac, 0, "fetch absolute failed:\n{}", ao);
    assert!(ao.contains("/bin/"), "expected shell paths in /etc/shells:\n{}", ao);
}

