    fn send_succeeds() {
        let p = profile();
        let officium = jjtlg_TestOfficium::new("nogit-send");
        let token = zjjtlg_bind_profile(&p, &officium);

        let (code, output) = jjrlg_run_send(
            jjrlg_SendArgs {
                legatio: token,
                command: "echo nogit_works".to_string(),
