    jjrlg_BindArgs, jjrlg_run_bind,
    jjrlg_SendArgs, jjrlg_run_send,
    jjrlg_PlantArgs, jjrlg_run_plant,
    jjrlg_FetchArgs, jjrlg_run_fetch,
    jjrlg_RelayArgs, jjrlg_run_relay,
    jjrlg_CheckArgs, jjrlg_run_check,
};

